sql:
SELECT r.result_id, r.experiment_id
FROM results r
INNER JOIN result_standard_deviations rsd ON r.result_id = rsd.result_id;

SELECT classifier_name, library_used, version
FROM classifiers
WHERE classifier_name = 'KNN';

SELECT classifier_name 
FROM classifiers 
WHERE library_used = 'scikit-learn';

external_knowledge:
- 'Exceptionally well' in this context refers to average performance greater than 0.85;
- 'Excellent average performance and consistency' is interpreted as having an average performance over 0.85 and a maximum standard deviation under 0.1.;
- The 'experiments conducted in 2022' implies the start date after '2022-01-01' and end date before '2022-12-31'.

sql:
SELECT AVG(value)
FROM result_values
WHERE description = 'Result for classifier 1';

SELECT classifier_name
FROM classifiers
WHERE classifier_id IN (2, 4);

SELECT classifier_id, RTRIM(description) AS trimmed_description 
FROM classifiers 
WHERE classifier_id > 5;

